        : title && eventScreenViewV2(title);
    }
    handleAfterDispatch?.();
  }, [
    route?.params?.analytics,
    analytic,
    title,
    handleAfterDispatch,
  ]);

  useEffect(() => {
    if (isFocused) {
      dispatchEventFocus();
    }
  }, [
    isFocused,
    dispatchEventFocus,
  ]);
};

